const input = $json || {};
let payload = input;
if (input.body && typeof input.body === 'object') payload = input.body;
if (typeof payload.payload === 'string') {
  try { payload = JSON.parse(payload.payload); } catch (e) {}
} else if (payload.payload && typeof payload.payload === 'object') {
  payload = payload.payload;
}
const branding = payload.branding && typeof payload.branding === 'object' ? payload.branding : {};
const inherited = payload.inherited && typeof payload.inherited === 'object' ? payload.inherited : {};
const clean = (v) => (v ?? '').toString().trim();
const toInt = (v) => {
  const n = Number(v);
  return Number.isInteger(n) && n > 0 ? n : '';
};
const navItems = Array.isArray(branding.nav_items)
  ? branding.nav_items.map((x) => clean(x)).filter(Boolean)
  : clean(branding.nav_items).split(',').map((x) => x.trim()).filter(Boolean);
const config = {
  template_id: clean(payload.template_id || payload.templateId || payload.template || ''),
  template_name: clean(branding.template_name || ''),
  theme_mode: clean(branding.theme_mode || branding.themeMode || ''),
  color_primary: clean(branding.color_primary),
  color_secondary: clean(branding.color_secondary),
  color_background: clean(branding.color_background),
  color_surface: clean(branding.color_surface),
  color_text: clean(branding.color_text),
  cta_label: clean(branding.cta_label),
  logo_width: Number(branding.logo_width || 0) || 0,
  font_pair: clean(branding.font_pair),
  nav_items: navItems,
  hero_badge: clean(branding.hero_badge),
  hero_title: clean(branding.hero_title),
  hero_subtitle: clean(branding.hero_subtitle),
  booking_title: clean(branding.booking_title),
  booking_subtitle: clean(branding.booking_subtitle),
  benefit_1: clean(branding.benefit_1),
  benefit_2: clean(branding.benefit_2),
  benefit_3: clean(branding.benefit_3),
  footer_note: clean(branding.footer_note),
  hero_image_url: clean(branding.hero_image_url),
  image_secondary_url: clean(branding.image_secondary_url),
  image_tertiary_url: clean(branding.image_tertiary_url)
};
const encoded = Buffer.from(JSON.stringify(config), 'utf8').toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '');
return [{
  json: {
    barberia_id: toInt(payload.barberia_id || payload.barberiaId || inherited.barberia_id),
    slug: clean(payload.slug || inherited.slug),
    nombre: clean(inherited.nombre || payload.nombre),
    logo_url: clean(branding.logo_url),
    cover_url: clean(branding.cover_url || branding.hero_image_url),
    ciudad: clean(branding.location_city || inherited.ciudad),
    direccion: clean(branding.location_address || inherited.direccion),
    telefono: clean(branding.location_phone || inherited.telefono),
    color_primary: clean(branding.color_primary),
    color_secondary: clean(branding.color_secondary),
    color_background: clean(branding.color_background),
    color_text: clean(branding.color_text),
    config_url: `ba://landing-config/${encoded}`
  }
}];

